bool TreeEntryImplementation::isInRange(float x, float y, float z, float range) {
	// server/zone/TreeEntry.idl():  		float rangeSq = range * range;
	float rangeSq = range * range;
	// server/zone/TreeEntry.idl():  		float deltaX = x - coordinates.getPositionX();
	float deltaX = x - (&coordinates)->getPositionX();
	// server/zone/TreeEntry.idl():  		float deltaY = y - coordinates.getPositionY();
	float deltaY = y - (&coordinates)->getPositionY();
	// server/zone/TreeEntry.idl():  		float deltaZ = z - coordinates.getPositionZ();
	float deltaZ = z - (&coordinates)->getPositionZ();
	// server/zone/TreeEntry.idl():  		float deltaCalc = (deltaX * deltaX) + (deltaY * deltaY) + (deltaZ * deltaZ);
	float deltaCalc = (deltaX * deltaX) + (deltaY * deltaY) + (deltaZ * deltaZ);
	// server/zone/TreeEntry.idl():  		return deltaCalc < rangeSq;
	return deltaCalc < rangeSq;
}

bool TreeEntryImplementation::isInRange(float x, float y, float range) {
	// server/zone/TreeEntry.idl():  		float rangesq = range * range;
	float rangesq = range * range;
	// server/zone/TreeEntry.idl():  		float deltaX = x - coordinates.getPositionX();
	float deltaX = x - (&coordinates)->getPositionX();
	// server/zone/TreeEntry.idl():  		float deltaY = y - coordinates.getPositionY();
	float deltaY = y - (&coordinates)->getPositionY();
	// server/zone/TreeEntry.idl():  			return false;
	if (deltaX * deltaX + deltaY * deltaY <= rangesq)	// server/zone/TreeEntry.idl():  			return true;
	return true;

	else 	// server/zone/TreeEntry.idl():  			return false;
	return false;
}

