	float y = obj->getPositionY();
	// server/zone/TreeEntry.idl():  		float z = obj.getPositionZ();
	float z = obj->getPositionZ();
	// server/zone/TreeEntry.idl():  		float deltaX = x - coordinates.getPositionX();
	float deltaX = x - (&coordinates)->getPositionX();
	// server/zone/TreeEntry.idl():  		float deltaY = y - coordinates.getPositionY();
	float deltaY = y - (&coordinates)->getPositionY();
	// server/zone/TreeEntry.idl():  		float deltaZ = z - coordinates.getPositionZ();
	float deltaZ = z - (&coordinates)->getPositionZ();
	// server/zone/TreeEntry.idl():  		return Math.sqrt(deltaX * deltaX + deltaY * deltaY);
